def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    result = [row[:] for row in grid]
    # Find 5-rectangles (connected components of 5)
    visited = set()
    rectangles = []
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 5 and (r, c) not in visited:
                comp = set()
                stack = [(r, c)]
                while stack:
                    cr, cc = stack.pop()
                    if (cr, cc) in comp:
                        continue
                    comp.add((cr, cc))
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 5 and (nr, nc) not in comp:
                            stack.append((nr, nc))
                visited |= comp
                min_r = min(cr for cr, cc in comp)
                max_r = max(cr for cr, cc in comp)
                min_c = min(cc for cr, cc in comp)
                max_c = max(cc for cr, cc in comp)
                holes = []
                for hr in range(min_r, max_r+1):
                    for hc in range(min_c, max_c+1):
                        if grid[hr][hc] != 5 and (hr, hc) not in comp:
                            holes.append((hr, hc))
                if holes:
                    rectangles.append({
                        'cells': comp, 'holes': holes,
                        'min_r': min_r, 'max_r': max_r, 'min_c': min_c, 'max_c': max_c
                    })
    # Find colored patches (non-0, non-5, not inside any rectangle)
    rect_regions = set()
    for rect in rectangles:
        for r in range(rect['min_r'], rect['max_r']+1):
            for c in range(rect['min_c'], rect['max_c']+1):
                rect_regions.add((r, c))
    color_visited = set()
    patches = []
    for r in range(rows):
        for c in range(cols):
            val = grid[r][c]
            if val != 0 and val != 5 and val != 7 and (r, c) not in color_visited and (r, c) not in rect_regions:
                comp = []
                stack = [(r, c)]
                while stack:
                    cr, cc = stack.pop()
                    if (cr, cc) in color_visited:
                        continue
                    if grid[cr][cc] != val:
                        continue
                    color_visited.add((cr, cc))
                    comp.append((cr, cc))
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if 0 <= nr < rows and 0 <= nc < cols and (nr, nc) not in color_visited:
                            stack.append((nr, nc))
                if comp:
                    patches.append({
                        'color': val, 'cells': comp,
                        'min_r': min(cr for cr, cc in comp),
                        'max_r': max(cr for cr, cc in comp),
                        'min_c': min(cc for cr, cc in comp),
                        'max_c': max(cc for cr, cc in comp)
                    })
    # Match patches to rectangles by hole shape
    for patch in patches:
        ph = patch['max_r'] - patch['min_r'] + 1
        pw = patch['max_c'] - patch['min_c'] + 1
        patch_shape = set()
        for r, c in patch['cells']:
            patch_shape.add((r - patch['min_r'], c - patch['min_c']))
        for rect in rectangles:
            hole_min_r = min(hr for hr, hc in rect['holes'])
            hole_max_r = max(hr for hr, hc in rect['holes'])
            hole_min_c = min(hc for hr, hc in rect['holes'])
            hole_max_c = max(hc for hr, hc in rect['holes'])
            hole_h = hole_max_r - hole_min_r + 1
            hole_w = hole_max_c - hole_min_c + 1
            if hole_h == ph and hole_w == pw:
                hole_shape = set()
                for hr, hc in rect['holes']:
                    hole_shape.add((hr - hole_min_r, hc - hole_min_c))
                if hole_shape == patch_shape:
                    for hr, hc in rect['holes']:
                        result[hr][hc] = patch['color']
                    for r, c in patch['cells']:
                        result[r][c] = 0
                    break
    return result

