def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    result = [row[:] for row in grid]
    cells = {}
    for r in range(rows):
        for c in range(cols):
            v = grid[r][c]
            if v != 0:
                if v not in cells:
                    cells[v] = []
                cells[v].append((r, c))
    colors = list(cells.keys())
    if len(cells[colors[0]]) < len(cells[colors[1]]):
        point_color, body_color = colors[0], colors[1]
    else:
        point_color, body_color = colors[1], colors[0]
    pr, pc = cells[point_color][0]
    body = cells[body_color]
    body_cr = sum(r for r, c in body) / len(body)
    body_cc = sum(c for r, c in body) / len(body)
    # Direction from point toward body center (and beyond)
    dr = body_cr - pr
    dc = body_cc - pc
    if abs(dr) > abs(dc):
        direction = (1 if dr > 0 else -1, 0)
    else:
        direction = (0, 1 if dc > 0 else -1)
    # Extend line from past the body to the edge of grid
    nr, nc = pr + direction[0], pc + direction[1]
    while 0 <= nr < rows and 0 <= nc < cols:
        if result[nr][nc] == 0:
            result[nr][nc] = point_color
        nr += direction[0]
        nc += direction[1]
    return result

