def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    # Find 2x2 blocks of 2
    blocks = []
    block_cells = set()
    for r in range(rows-1):
        for c in range(cols-1):
            if grid[r][c]==2 and grid[r][c+1]==2 and grid[r+1][c]==2 and grid[r+1][c+1]==2:
                blocks.append((r,c))
                block_cells.update([(r,c),(r,c+1),(r+1,c),(r+1,c+1)])
    # BFS from block 0 through 8s to see if it reaches block 1
    b2_cells = set()
    br2, bc2 = blocks[1]
    b2_cells = {(br2,bc2),(br2,bc2+1),(br2+1,bc2),(br2+1,bc2+1)}
    # Get starting points: cells adjacent to block 0 that are 8
    br, bc = blocks[0]
    starts = set()
    for r, c in [(br,bc),(br,bc+1),(br+1,bc),(br+1,bc+1)]:
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0<=nr<rows and 0<=nc<cols and (nr,nc) not in block_cells and grid[nr][nc]==8:
                starts.add((nr,nc))
    visited = set()
    stack = list(starts)
    reached = False
    while stack:
        cr, cc = stack.pop()
        if (cr, cc) in visited:
            continue
        visited.add((cr, cc))
        # Check if adjacent to block 2
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            if (cr+dr, cc+dc) in b2_cells:
                reached = True
                break
        if reached:
            break
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = cr+dr, cc+dc
            if 0<=nr<rows and 0<=nc<cols and (nr,nc) not in visited and (nr,nc) not in block_cells and grid[nr][nc]==8:
                stack.append((nr,nc))
    return [[8]] if reached else [[0]]
